import{_ as e,o as l,c as a,a7 as d}from"./chunks/framework.C5fSpjcB.js";const h=JSON.parse('{"title":"超維（Ultra）","description":"","frontmatter":{},"headers":[],"relativePath":"ja/realms/ultra.md","filePath":"ja/realms/ultra.md","lastUpdated":1775394001000}'),n={name:"ja/realms/ultra.md"};function r(i,t,s,x,g,y){return l(),a("div",null,[...t[0]||(t[0]=[d('<h1 id="超維-ultra" tabindex="-1">超維（Ultra） <a class="header-anchor" href="#超維-ultra" aria-label="Permalink to &quot;超維（Ultra）&quot;">​</a></h1><p><span class="realm-badge realm-ultra">超維</span></p><p><strong>超維</strong>はクトゥルフ神話における次元超越やヨグ＝ソトースの全知をテーマとした界域です。超維空間システムによる追加ターンを活用するテクニカルな戦闘スタイルが特徴です。</p><h2 id="テーマ・世界観" tabindex="-1">テーマ・世界観 <a class="header-anchor" href="#テーマ・世界観" aria-label="Permalink to &quot;テーマ・世界観&quot;">​</a></h2><p>超維界域はヨグ＝ソトースに代表される時空を超越した存在の力を宿す領域です。覚醒体たちは次元の狭間から力を汲み上げ、通常の制約を超えたカードプレイを実現します。</p><h2 id="戦闘スタイル" tabindex="-1">戦闘スタイル <a class="header-anchor" href="#戦闘スタイル" aria-label="Permalink to &quot;戦闘スタイル&quot;">​</a></h2><ul><li><strong>超維空間</strong> — 超維界域才能発動後、チーム上部に「超維空間」が表示。毎ターン最初にプレイした指令カードの副本が蓄積され、上限到達で追加の超維ターンに突入。超維ターン中は蓄積した全カードが手札になる</li><li><strong>純超維共鳴</strong> — 純超維編成時、熟練度効果が2倍。追加ターン中の能力減少ペナルティが完全無効化</li><li><strong>算力操作</strong> — 算力を追加回復するカードが豊富</li><li><strong>ドロー加速</strong> — 追加ドローでデッキの回転率を上げる</li><li><strong>テクニカル</strong> — プレイング難度が高いが、上限火力も高い</li></ul><h2 id="超維界域の覚醒体" tabindex="-1">超維界域の覚醒体 <a class="header-anchor" href="#超維界域の覚醒体" aria-label="Permalink to &quot;超維界域の覚醒体&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">覚醒体名</th><th style="text-align:center;">レア</th><th style="text-align:center;">役割</th><th style="text-align:center;">Tier</th><th style="text-align:left;">入手</th></tr></thead><tbody><tr><td style="text-align:left;">艾瑞卡 (Erica)</td><td style="text-align:center;">SSR</td><td style="text-align:center;">防御型</td><td style="text-align:center;">T0</td><td style="text-align:left;">無料</td></tr><tr><td style="text-align:left;">莉兹 (Liz)</td><td style="text-align:center;">SSR</td><td style="text-align:center;">攻撃型</td><td style="text-align:center;">T0</td><td style="text-align:left;">活動</td></tr><tr><td style="text-align:left;">达芙黛尔 (Daffodil)</td><td style="text-align:center;">SSR</td><td style="text-align:center;">攻撃型</td><td style="text-align:center;">T0</td><td style="text-align:left;">限定</td></tr><tr><td style="text-align:left;">温柯尔 (Winkle)</td><td style="text-align:center;">SSR</td><td style="text-align:center;">支援型</td><td style="text-align:center;">T1</td><td style="text-align:left;">常驻</td></tr><tr><td style="text-align:left;">卡茜亚 (Casiah)</td><td style="text-align:center;">SSR</td><td style="text-align:center;">副攻撃型</td><td style="text-align:center;">T1</td><td style="text-align:left;">常驻</td></tr><tr><td style="text-align:left;">詹金 (Jenkins)</td><td style="text-align:center;">SSR</td><td style="text-align:center;">副攻撃型</td><td style="text-align:center;">T1</td><td style="text-align:left;">常驻</td></tr><tr><td style="text-align:left;">汀克特 (Tincture)</td><td style="text-align:center;">SSR</td><td style="text-align:center;">支援型</td><td style="text-align:center;">T2</td><td style="text-align:left;">常驻</td></tr><tr><td style="text-align:left;">奥尔拉 (Horla)</td><td style="text-align:center;">SSR</td><td style="text-align:center;">支援型</td><td style="text-align:center;">—</td><td style="text-align:left;">活動</td></tr><tr><td style="text-align:left;">旺达 (Wanda)</td><td style="text-align:center;">SSR</td><td style="text-align:center;">防御型</td><td style="text-align:center;">—</td><td style="text-align:left;">唤醒</td></tr><tr><td style="text-align:left;">克莱门汀 (Clementine)</td><td style="text-align:center;">SSR</td><td style="text-align:center;">支援型</td><td style="text-align:center;">—</td><td style="text-align:left;">限定</td></tr><tr><td style="text-align:left;">卡斯托尔 (Castor)</td><td style="text-align:center;">SSR</td><td style="text-align:center;">防御型</td><td style="text-align:center;">—</td><td style="text-align:left;">限定</td></tr><tr><td style="text-align:left;">波吕克斯 (Pollux)</td><td style="text-align:center;">SSR</td><td style="text-align:center;">攻撃型</td><td style="text-align:center;">—</td><td style="text-align:left;">限定</td></tr><tr><td style="text-align:left;">阿拉克涅 (Arachne)</td><td style="text-align:center;">SSR</td><td style="text-align:center;">攻撃型</td><td style="text-align:center;">—</td><td style="text-align:left;">限定（v2.5予告）</td></tr></tbody></table><h2 id="おすすめ編成" tabindex="-1">おすすめ編成 <a class="header-anchor" href="#おすすめ編成" aria-label="Permalink to &quot;おすすめ編成&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>超維界域は追加ターンを獲得できることが最大の強み。出力空間と緩衝時間を効果的に提供します。操作難度はやや高めですが、上限性能は十分に高いです。</p></div><h3 id="超維毒チーム-新規プレイヤー推奨" tabindex="-1">超維毒チーム（新規プレイヤー推奨） <a class="header-anchor" href="#超維毒チーム-新規プレイヤー推奨" aria-label="Permalink to &quot;超維毒チーム（新規プレイヤー推奨）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">枠</th><th style="text-align:left;">キャラ</th><th style="text-align:left;">役割</th></tr></thead><tbody><tr><td style="text-align:center;">毒傷DPS（必須）</td><td style="text-align:left;">旺达 (Wanda)</td><td style="text-align:left;">メインアタッカー</td></tr><tr><td style="text-align:center;">蓄エネ補助（1覚醒）</td><td style="text-align:left;">诺缔拉 (Nodera)</td><td style="text-align:left;">蓄エネサポート</td></tr><tr><td style="text-align:center;">シールド（無料キャラ）</td><td style="text-align:left;">艾瑞卡 (Erica)</td><td style="text-align:left;">護盾</td></tr><tr><td style="text-align:center;">毒スタック/ツール</td><td style="text-align:left;">宁菲亚 (Nymphia) / 温柯尔 (Winkle)</td><td style="text-align:left;">毒付与・ツール</td></tr></tbody></table><p>旺达以外は代替可能。界域精通100以上推奨。宁菲亚+毒タロットでボスの無限遅延が可能。</p><h3 id="超維初始四小只" tabindex="-1">超維初始四小只 <a class="header-anchor" href="#超維初始四小只" aria-label="Permalink to &quot;超維初始四小只&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">枠</th><th style="text-align:left;">キャラ</th><th style="text-align:left;">役割</th></tr></thead><tbody><tr><td style="text-align:center;">DPS（1覚醒）</td><td style="text-align:left;">莉兹 (Liz)</td><td style="text-align:left;">火力</td></tr><tr><td style="text-align:center;">シールド</td><td style="text-align:left;">艾瑞卡 (Erica)</td><td style="text-align:left;">護盾</td></tr><tr><td style="text-align:center;">嘲諷/ツール</td><td style="text-align:left;">奥吉尔 (Ogier)</td><td style="text-align:left;">タンク</td></tr><tr><td style="text-align:center;">浄化</td><td style="text-align:left;">朵尔 (Doll)</td><td style="text-align:left;">クレンズ</td></tr></tbody></table><p>全員無料/初始キャラ。毒スタックで生存可能。ただし現環境では莉兹毒チームのメタは深海/血肉に追い越されているため、過度な投資に注意。</p><h3 id="超維ダブルc・ダブルシールド" tabindex="-1">超維ダブルC・ダブルシールド <a class="header-anchor" href="#超維ダブルc・ダブルシールド" aria-label="Permalink to &quot;超維ダブルC・ダブルシールド&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">枠</th><th style="text-align:left;">キャラ</th><th style="text-align:left;">役割</th></tr></thead><tbody><tr><td style="text-align:center;">DPS</td><td style="text-align:left;">温柯尔 (Winkle)</td><td style="text-align:left;">飛蛾火で緑炎スタック</td></tr><tr><td style="text-align:center;">シールド</td><td style="text-align:left;">艾瑞卡 (Erica)</td><td style="text-align:left;">超限でシールド獲得</td></tr><tr><td style="text-align:center;">DPS</td><td style="text-align:left;">莉兹 (Liz)</td><td style="text-align:left;">火力</td></tr><tr><td style="text-align:center;">フレキシブル</td><td style="text-align:left;">弾性枠</td><td style="text-align:left;">—</td></tr></tbody></table><p>多段攻撃時は温柯尔の飛蛾火で緑炎をスタックしてから、艾瑞卡の超限でシールドを獲得する流れ。</p><h2 id="関連ページ" tabindex="-1">関連ページ <a class="header-anchor" href="#関連ページ" aria-label="Permalink to &quot;関連ページ&quot;">​</a></h2><ul><li><a href="./">界域概要</a></li><li><a href="./chaos.html">混沌（Chaos）</a></li><li><a href="./aequor.html">深海（Aequor）</a></li><li><a href="./caro.html">血肉（Caro）</a></li><li><a href="./../awakeners/team-building.html">編成ガイド</a></li></ul>',22)])])}const o=e(n,[["render",r]]);export{h as __pageData,o as default};
